html = "<!doctype html>\n<html>\n<head>\n<meta charset=\"utf-8\">\n<style>\n:root{\n  --bg:#070910;\n  --grid_line:#4a3510;\n  --cell_bg:#172033;\n  --cell_bg_2:#1b2740;\n  --cell_marked:#138a52;\n  --cell_free:#532e86;\n  --gold:#ffd166;\n  --gold2:#ffb703;\n  --red:#ef476f;\n  --blue:#4cc9f0;\n  --green:#06d6a0;\n  --purple:#b517ff;\n  --text:#f8fafc;\n  --muted:#a8b3c7;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0;\n  padding:0;\n  width:100%;\n  height:100%;\n  background:var(--bg);\n  color:var(--text);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  overflow:hidden;\n}\n.app{\n  width:535px;\n  height:620px;\n  max-width:100vw;\n  max-height:100vh;\n  margin:0 auto;\n  background:var(--bg);\n  display:flex;\n  flex-direction:column;\n}\n.header{\n  background:var(--bg);\n  display:flex;\n  align-items:flex-start;\n  justify-content:center;\n  padding-top:7px;\n  flex:0 0 auto;\n}\n.dice{\n  width:auto;\n  min-width:31px;\n  margin-left:8px;\n  margin-right:8px;\n  background:var(--bg);\n  color:var(--gold);\n  font-family:\"Segoe UI Symbol\",\"Segoe UI\",Arial,sans-serif;\n  font-size:24px;\n  line-height:29px;\n  text-align:center;\n}\n.title_wrap{\n  background:var(--bg);\n  text-align:center;\n  flex:0 0 auto;\n}\n.title{\n  background:var(--bg);\n  color:var(--gold);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:18px;\n  line-height:22px;\n  font-weight:700;\n  text-align:center;\n  white-space:nowrap;\n}\n.subtitle{\n  background:var(--bg);\n  color:var(--muted);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:11px;\n  line-height:14px;\n  font-weight:700;\n  text-align:center;\n  white-space:nowrap;\n}\n.controls{\n  background:var(--bg);\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  gap:4px;\n  margin-top:4px;\n  margin-bottom:4px;\n  flex:0 0 auto;\n}\n.casino_btn{\n  background:#251a08;\n  color:var(--gold);\n  border:0;\n  outline:0;\n  padding:4px 8px;\n  margin:0;\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:8px;\n  font-weight:700;\n  line-height:12px;\n  cursor:pointer;\n  min-height:20px;\n}\n.casino_btn:hover{\n  background:#4a320b;\n  color:#fff4c7;\n}\n.casino_btn:active{\n  background:#4a320b;\n  color:#fff4c7;\n}\n.neon_bar{\n  background:var(--gold);\n  height:2px;\n  margin-left:36px;\n  margin-right:36px;\n  margin-top:0;\n  margin-bottom:4px;\n  flex:0 0 auto;\n}\n.outer{\n  background:var(--gold2);\n  margin-left:8px;\n  margin-right:8px;\n  margin-top:6px;\n  margin-bottom:6px;\n  padding:0;\n  flex:1 1 auto;\n  min-height:0;\n  display:flex;\n}\n.inner{\n  background:#2b210e;\n  margin:2px;\n  padding:0;\n  flex:1 1 auto;\n  min-height:0;\n  display:flex;\n}\n.grid_frame{\n  background:var(--grid_line);\n  margin:2px;\n  padding:0;\n  flex:1 1 auto;\n  min-height:0;\n  display:grid;\n  grid-template-columns:repeat(5,1fr);\n  grid-template-rows:repeat(5,1fr);\n}\n.cell{\n  margin:1px;\n  border:0;\n  outline:0;\n  background:var(--cell_bg);\n  color:var(--text);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:8px;\n  line-height:1.12;\n  font-weight:700;\n  text-align:center;\n  white-space:pre-line;\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  padding:1px 2px;\n  overflow:hidden;\n  cursor:pointer;\n  user-select:none;\n}\n.cell.alt{\n  background:var(--cell_bg_2);\n}\n.cell:hover:not(.free){\n  background:#263554;\n  color:#ffffff;\n}\n.cell.free{\n  background:var(--cell_free)!important;\n  color:var(--gold)!important;\n  font-size:11px;\n  font-weight:700;\n  font-style:italic;\n  cursor:default;\n}\n.cell.free:hover{\n  background:var(--cell_free)!important;\n  color:var(--gold)!important;\n}\n.cell.marked{\n  background:var(--cell_marked)!important;\n  color:#ecfff4!important;\n}\n.cell.select_anim{\n  animation:selectPop .18s ease;\n}\n@keyframes selectPop{\n  0%{transform:scale(.96);filter:brightness(1.28)}\n  70%{transform:scale(1.035);filter:brightness(1.12)}\n  100%{transform:scale(1);filter:brightness(1)}\n}\n.status{\n  background:var(--bg);\n  color:var(--muted);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:8px;\n  line-height:14px;\n  text-align:center;\n  padding-top:0;\n  padding-bottom:5px;\n  flex:0 0 auto;\n}\n.overlay{\n  position:fixed;\n  left:0;\n  top:0;\n  right:0;\n  bottom:0;\n  background:#000000;\n  display:none;\n  z-index:50;\n}\n.overlay.show{\n  display:block;\n}\n.rules_card{\n  position:absolute;\n  left:50%;\n  top:50%;\n  transform:translate(-50%,-50%);\n  width:78%;\n  height:45%;\n  background:#141a24;\n  color:var(--text);\n  text-align:center;\n}\n.rules_title{\n  margin-top:20px;\n  margin-bottom:8px;\n  color:var(--gold);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:26px;\n  line-height:32px;\n  font-weight:700;\n}\n.rules_body{\n  display:inline-block;\n  margin-top:6px;\n  color:var(--text);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:12px;\n  line-height:18px;\n  font-weight:700;\n  text-align:left;\n}\n.rules_hint{\n  margin-top:10px;\n  color:var(--muted);\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:9px;\n  line-height:14px;\n}\n.bingo_text{\n  position:absolute;\n  left:50%;\n  top:43%;\n  transform:translate(-50%,-50%);\n  color:var(--gold);\n  background:#000000;\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:50px;\n  line-height:60px;\n  font-weight:700;\n  white-space:nowrap;\n  text-align:center;\n}\n.bingo_sub{\n  position:absolute;\n  left:50%;\n  top:56%;\n  transform:translate(-50%,-50%);\n  color:var(--text);\n  background:#000000;\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:15px;\n  line-height:22px;\n  font-weight:700;\n  white-space:nowrap;\n}\n.bingo_hint{\n  position:absolute;\n  left:50%;\n  top:65%;\n  transform:translate(-50%,-50%);\n  color:var(--muted);\n  background:#000000;\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-size:9px;\n  line-height:14px;\n  white-space:nowrap;\n}\n.star{\n  position:absolute;\n  background:#000000;\n  pointer-events:none;\n  z-index:52;\n  font-family:\"Segoe UI\",Arial,sans-serif;\n  font-weight:700;\n}\n.status{\n  display:none!important;\n}\n</style>\n</head>\n<body>\n<div class=\"app\" id=\"app\">\n  <div class=\"header\">\n    <div class=\"dice\" id=\"leftDice\">&#9860;</div>\n    <div class=\"title_wrap\">\n      <div class=\"title\" id=\"title\">&#10022; Wings of Glory &#10022;</div>\n      <div class=\"subtitle\">LOW RANK BINGO</div>\n    </div>\n    <div class=\"dice\" id=\"rightDice\">&#9858;</div>\n  </div>\n\n  <div class=\"controls\">\n    <button class=\"casino_btn\" onclick=\"rollClicked()\">Roll &#127922;</button>\n    <button class=\"casino_btn\" onclick=\"resetMarks()\">Reset</button>\n    <button class=\"casino_btn\" onclick=\"showRules()\">Bingo?</button>\n    <button class=\"casino_btn\" onclick=\"fullscreenToggle()\">Full</button>\n  </div>\n\n  <div class=\"neon_bar\" id=\"neonBar\"></div>\n\n  <div class=\"outer\">\n    <div class=\"inner\">\n      <div class=\"grid_frame\" id=\"gridFrame\"></div>\n    </div>\n  </div>\n\n  <div class=\"status\" id=\"status\">Roll, mark squares, chase bingo.</div>\n</div>\n\n<div class=\"overlay\" id=\"rulesOverlay\" onclick=\"hideRules()\">\n  <div class=\"rules_card\" id=\"rulesCard\">\n    <div class=\"rules_title\">RULES</div>\n    <div class=\"rules_body\">&bull; Click a square when it happens<br>&bull; FREE SPACE is already marked<br>&bull; 5 in a row = BINGO<br>&bull; Rows, columns, diagonals count<br>&bull; Roll makes a new random board</div>\n    <div class=\"rules_hint\">click anywhere or press Esc to close</div>\n  </div>\n</div>\n\n<div class=\"overlay\" id=\"bingoOverlay\" onclick=\"hideBingoOverlay()\">\n  <div class=\"bingo_text\" id=\"bingoText\">BINGO!</div>\n  <div class=\"bingo_sub\">JACKPOT HIT</div>\n  <div class=\"bingo_hint\">click anywhere or press Esc to close</div>\n</div>\n\n<script>\nconst BINGO_ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\n\nconst COLORS = {\n  bg:\"#070910\",\n  gridLine:\"#4a3510\",\n  cellBg:\"#172033\",\n  cellBg2:\"#1b2740\",\n  cellMarked:\"#138a52\",\n  cellFree:\"#532e86\",\n  gold:\"#ffd166\",\n  gold2:\"#ffb703\",\n  red:\"#ef476f\",\n  blue:\"#4cc9f0\",\n  green:\"#06d6a0\",\n  purple:\"#b517ff\",\n  text:\"#f8fafc\",\n  muted:\"#a8b3c7\"\n};\n\nlet buttons = [];\nlet marked = new Set([12]);\nlet diceFaces = [9856,9857,9858,9859,9860,9861];\nlet animating = false;\nlet idleTick = 0;\nlet boardHasBingo = false;\nlet bingoRunning = false;\nlet rulesPulseRunning = false;\n\nfunction cp(n){ return String.fromCodePoint(n); }\n\nfunction randomChoice(arr){\n  return arr[Math.floor(Math.random()*arr.length)];\n}\n\nfunction shuffle(arr){\n  const a = arr.slice();\n  for(let i=a.length-1;i>0;i--){\n    const j = Math.floor(Math.random()*(i+1));\n    const t = a[i];\n    a[i] = a[j];\n    a[j] = t;\n  }\n  return a;\n}\n\nfunction buildUi(){\n  const grid = document.getElementById(\"gridFrame\");\n  grid.innerHTML = \"\";\n  buttons = [];\n  for(let row=0; row<5; row++){\n    const rowButtons = [];\n    for(let col=0; col<5; col++){\n      const index = row*5 + col;\n      const btn = document.createElement(\"div\");\n      btn.className = \"cell\";\n      btn.dataset.index = index;\n      btn.onclick = function(){ toggleCell(index); };\n      grid.appendChild(btn);\n      rowButtons.push(btn);\n    }\n    buttons.push(rowButtons);\n  }\n}\n\nfunction generateItems(){\n  const items = shuffle(BINGO_ITEMS);\n  const board = [];\n  let itemI = 0;\n  for(let i=0;i<25;i++){\n    if(i===12){\n      board.push(\"FREE SPACE\");\n    }else{\n      board.push(items[itemI]);\n      itemI += 1;\n    }\n  }\n  return board;\n}\n\nfunction applyBoard(board){\n  marked = new Set([12]);\n  boardHasBingo = false;\n\n  for(let row=0; row<5; row++){\n    for(let col=0; col<5; col++){\n      const index = row*5 + col;\n      const btn = buttons[row][col];\n      const item = board[index];\n\n      btn.originalText = item;\n      btn.style.background = \"\";\n      btn.style.color = \"\";\n      btn.className = \"cell\";\n\n      if(index === 12){\n        btn.className = \"cell free\";\n        btn.textContent = \"FREE\\nSPACE\";\n      }else{\n        if((row+col)%2===1){\n          btn.classList.add(\"alt\");\n        }\n        btn.textContent = item;\n      }\n    }\n  }\n  setTimeout(updateTextFit,20);\n}\n\nfunction wrapText(text,maxChars){\n  const words = text.split(/\\s+/);\n  const lines = [];\n  let line = \"\";\n\n  for(let i=0;i<words.length;i++){\n    const word = words[i];\n    if(!line){\n      line = word;\n    }else if(line.length + 1 + word.length <= maxChars){\n      line += \" \" + word;\n    }else{\n      lines.push(line);\n      line = word;\n    }\n  }\n  if(line) lines.push(line);\n  return lines.join(\"\\n\");\n}\n\nfunction updateTextFit(){\n  try{\n    const grid = document.getElementById(\"gridFrame\");\n    const cellW = Math.max(50, Math.floor(grid.clientWidth / 5) - 8);\n    const cellH = Math.max(45, Math.floor(grid.clientHeight / 5) - 8);\n\n    let fontSize = 10;\n    let maxChars = 12;\n\n    if(cellW < 78 || cellH < 68){\n      fontSize = 8;\n      maxChars = 10;\n    }else if(cellW < 100 || cellH < 85){\n      fontSize = 10;\n      maxChars = 11;\n    }else if(cellW < 120 || cellH < 100){\n      fontSize = 10;\n      maxChars = 12;\n    }\n\n    for(let row=0; row<5; row++){\n      for(let col=0; col<5; col++){\n        const btn = buttons[row][col];\n        const original = btn.originalText || btn.textContent;\n        if(row===2 && col===2){\n          btn.textContent = \"FREE\\nSPACE\";\n          btn.style.fontSize = Math.max(13,fontSize+3) + \"px\";\n          btn.style.fontWeight = \"700\";\n          btn.style.fontStyle = \"italic\";\n        }else{\n          btn.textContent = wrapText(original,maxChars);\n          btn.style.fontSize = fontSize + \"px\";\n          btn.style.fontWeight = \"700\";\n          btn.style.fontStyle = \"normal\";\n        }\n      }\n    }\n  }catch(e){}\n}\n\nfunction rollClicked(){\n  rollBoard(true);\n}\n\nfunction rollBoard(animated){\n  if(animating) return;\n\n  const finalBoard = generateItems();\n\n  if(!animated){\n    applyBoard(finalBoard);\n    return;\n  }\n\n  animating = true;\n  document.getElementById(\"status\").textContent = \"Rolling...\";\n  animateDice(0);\n  const steps = 14;\n\n  function spin(step){\n    const temp = generateItems();\n\n    for(let i=0;i<25;i++){\n      const r = Math.floor(i/5);\n      const c = i%5;\n      const btn = buttons[r][c];\n\n      if(i===12){\n        btn.originalText = \"FREE SPACE\";\n        btn.className = \"cell free\";\n        btn.textContent = \"FREE\\nSPACE\";\n        btn.style.background = \"\";\n        btn.style.color = \"\";\n      }else{\n        btn.originalText = temp[i];\n        btn.className = \"cell\";\n        if((r+c)%2===1){\n          btn.classList.add(\"alt\");\n        }\n        btn.style.background = randomChoice([COLORS.cellBg,COLORS.cellBg2,\"#2a1f3d\",\"#263554\"]);\n        btn.style.color = randomChoice([COLORS.text,COLORS.gold,COLORS.blue]);\n      }\n    }\n\n    updateTextFit();\n\n    if(step < steps){\n      setTimeout(function(){ spin(step+1); },30 + step*6);\n    }else{\n      for(let r=0;r<5;r++){\n        for(let c=0;c<5;c++){\n          buttons[r][c].style.background = \"\";\n          buttons[r][c].style.color = \"\";\n        }\n      }\n      applyBoard(finalBoard);\n      flashTitle(0);\n      document.getElementById(\"status\").textContent = \"Rolled. Click squares to mark.\";\n      animating = false;\n    }\n  }\n\n  spin(0);\n}\n\nfunction animateDice(step){\n  const left = document.getElementById(\"leftDice\");\n  const right = document.getElementById(\"rightDice\");\n\n  left.textContent = cp(randomChoice(diceFaces));\n  right.textContent = cp(randomChoice(diceFaces));\n  left.style.color = randomChoice([COLORS.gold,COLORS.blue,COLORS.red,COLORS.green]);\n  right.style.color = randomChoice([COLORS.gold,COLORS.blue,COLORS.red,COLORS.green]);\n\n  if(step < 18){\n    setTimeout(function(){ animateDice(step+1); },65);\n  }else{\n    left.textContent = cp(randomChoice(diceFaces));\n    right.textContent = cp(randomChoice(diceFaces));\n    left.style.color = COLORS.gold;\n    right.style.color = COLORS.gold;\n  }\n}\n\nfunction idleAnimation(){\n  const bingoOpen = document.getElementById(\"bingoOverlay\").classList.contains(\"show\");\n  const rulesOpen = document.getElementById(\"rulesOverlay\").classList.contains(\"show\");\n\n  if(!animating && !bingoOpen && !rulesOpen){\n    const colors = [COLORS.gold,COLORS.gold2,COLORS.blue,COLORS.green,COLORS.red,COLORS.purple];\n    const color = colors[idleTick % colors.length];\n\n    document.getElementById(\"neonBar\").style.background = color;\n    document.getElementById(\"leftDice\").style.color = idleTick%2===0 ? color : COLORS.gold;\n    document.getElementById(\"rightDice\").style.color = idleTick%2===1 ? color : COLORS.gold;\n\n    if(idleTick % 6 === 0){\n      document.getElementById(\"leftDice\").textContent = cp(randomChoice(diceFaces));\n      document.getElementById(\"rightDice\").textContent = cp(randomChoice(diceFaces));\n    }\n    idleTick += 1;\n  }\n\n  setTimeout(idleAnimation,650);\n}\n\nfunction flashTitle(n){\n  const title = document.getElementById(\"title\");\n  if(n >= 8){\n    title.style.color = COLORS.gold;\n    return;\n  }\n  title.style.color = n%2===0 ? COLORS.blue : COLORS.gold;\n  setTimeout(function(){ flashTitle(n+1); },100);\n}\n\nfunction resetMarks(){\n  marked = new Set([12]);\n  boardHasBingo = false;\n\n  for(let row=0; row<5; row++){\n    for(let col=0; col<5; col++){\n      const index = row*5 + col;\n      const btn = buttons[row][col];\n\n      btn.style.background = \"\";\n      btn.style.color = \"\";\n      btn.className = \"cell\";\n\n      if(index === 12){\n        btn.className = \"cell free\";\n      }else{\n        if((row+col)%2===1){\n          btn.classList.add(\"alt\");\n        }\n      }\n    }\n  }\n\n  document.getElementById(\"status\").textContent = \"Marks reset.\";\n}\n\nfunction toggleCell(index){\n  if(index === 12 || animating){\n    return;\n  }\n\n  const row = Math.floor(index/5);\n  const col = index%5;\n  const btn = buttons[row][col];\n\n  if(marked.has(index)){\n    marked.delete(index);\n    btn.style.background = \"\";\n    btn.style.color = \"\";\n    btn.className = \"cell\";\n    if((row+col)%2===1){\n      btn.classList.add(\"alt\");\n    }\n    btn.classList.remove(\"select_anim\");\n    void btn.offsetWidth;\n    btn.classList.add(\"select_anim\");\n    boardHasBingo = false;\n  }else{\n    marked.add(index);\n    btn.style.color = \"#ecfff4\";\n    pulseMark(btn,0);\n  }\n\n  if(hasBingo() && !boardHasBingo){\n    boardHasBingo = true;\n    showBingoOverlay();\n  }\n}\n\nfunction pulseMark(btn,step){\n  const colors = [\"#2ee88e\",\"#20b875\",COLORS.cellMarked];\n\n  if(step === 0){\n    btn.classList.remove(\"select_anim\");\n    void btn.offsetWidth;\n    btn.classList.add(\"select_anim\");\n  }\n\n  if(step >= colors.length){\n    btn.classList.add(\"marked\");\n    btn.style.background = \"\";\n    btn.style.color = \"\";\n    return;\n  }\n\n  btn.classList.add(\"marked\");\n  btn.style.background = colors[step];\n  btn.style.color = \"#ecfff4\";\n\n  setTimeout(function(){ pulseMark(btn,step+1); },70);\n}\n\nfunction hasBingo(){\n  const lines = [];\n\n  for(let row=0; row<5; row++){\n    lines.push([row*5,row*5+1,row*5+2,row*5+3,row*5+4]);\n  }\n\n  for(let col=0; col<5; col++){\n    lines.push([col,5+col,10+col,15+col,20+col]);\n  }\n\n  lines.push([0,6,12,18,24]);\n  lines.push([4,8,12,16,20]);\n\n  return lines.some(function(line){\n    return line.every(function(i){ return marked.has(i); });\n  });\n}\n\nfunction showRules(){\n  hideRules();\n  const layer = document.getElementById(\"rulesOverlay\");\n  layer.classList.add(\"show\");\n  rulesPulseRunning = true;\n  rulesPulse(0);\n}\n\nfunction rulesPulse(step){\n  const layer = document.getElementById(\"rulesOverlay\");\n  if(!layer.classList.contains(\"show\")){\n    return;\n  }\n\n  const card = document.getElementById(\"rulesCard\");\n  const colors = [\"#141a24\",\"#192234\",\"#141a24\"];\n  const bg = colors[step % colors.length];\n\n  card.style.background = bg;\n\n  if(step < 12){\n    setTimeout(function(){ rulesPulse(step+1); },120);\n  }\n}\n\nfunction hideRules(){\n  const layer = document.getElementById(\"rulesOverlay\");\n  layer.classList.remove(\"show\");\n  rulesPulseRunning = false;\n}\n\nfunction showBingoOverlay(){\n  hideBingoOverlay();\n  document.getElementById(\"bingoOverlay\").classList.add(\"show\");\n  bingoRunning = true;\n  bingoAnimation(0);\n}\n\nfunction bingoAnimation(step){\n  const layer = document.getElementById(\"bingoOverlay\");\n  if(!layer.classList.contains(\"show\")){\n    return;\n  }\n\n  const colors = [COLORS.gold,COLORS.blue,COLORS.red,COLORS.green,\"#ffffff\",COLORS.purple];\n  const sizes = [48,54,60,56,52,58];\n  const bingoText = document.getElementById(\"bingoText\");\n\n  bingoText.style.color = randomChoice(colors);\n  bingoText.style.fontSize = sizes[step % sizes.length] + \"px\";\n\n  if(step < 30){\n    for(let i=0; i<6; i++){\n      const star = document.createElement(\"div\");\n      star.className = \"star\";\n      const starCodes = [10022,10023,9733,9670,9679,9824,9829];\n      star.textContent = cp(randomChoice(starCodes));\n      star.style.fontSize = (10 + Math.floor(Math.random()*13)) + \"px\";\n      star.style.color = randomChoice(colors);\n      star.style.left = (Math.random()*100) + \"%\";\n      star.style.top = (Math.random()*100) + \"%\";\n      document.getElementById(\"bingoOverlay\").appendChild(star);\n      setTimeout(function(){ star.remove(); },550);\n    }\n\n    setTimeout(function(){ bingoAnimation(step+1); },85);\n  }else{\n    bingoText.style.color = COLORS.gold;\n    bingoText.style.fontSize = \"56px\";\n  }\n}\n\nfunction hideBingoOverlay(){\n  const layer = document.getElementById(\"bingoOverlay\");\n  const stars = layer.querySelectorAll(\".star\");\n  for(let i=0; i<stars.length; i++){\n    stars[i].remove();\n  }\n  layer.classList.remove(\"show\");\n  bingoRunning = false;\n}\n\nfunction fullscreenToggle(){\n  try{\n    if(document.fullscreenElement){\n      document.exitFullscreen();\n    }else{\n      document.documentElement.requestFullscreen();\n    }\n  }catch(e){}\n}\n\nfunction closeOverlayOrFullscreen(){\n  if(document.getElementById(\"bingoOverlay\").classList.contains(\"show\")){\n    hideBingoOverlay();\n  }else if(document.getElementById(\"rulesOverlay\").classList.contains(\"show\")){\n    hideRules();\n  }else if(document.fullscreenElement){\n    document.exitFullscreen();\n  }\n}\n\ndocument.addEventListener(\"keydown\",function(e){\n  if(e.key === \"Escape\"){\n    closeOverlayOrFullscreen();\n  }\n});\n\nwindow.addEventListener(\"resize\",function(){\n  setTimeout(updateTextFit,20);\n});\n\nbuildUi();\nrollBoard(false);\nidleAnimation();\n</script>\n</body>\n</html>\n"

